/**
 * Basic tokenizer that splits text by whitespace.
 *
 * Supports lowercase normalization, length filtering,
 * truncation, and punctuation stripping.
 */
class WhitespaceTokenizer(
  lowercase: Boolean = false,
  minLength: Int = 0,
  maxLength: Option[Int] = None,
  stripPunctuation: Boolean = false
) {
  private val punctuation: Set[Char] = \".,"'!?;:'"'\\\\\"()[]{}\".toSet

  private def processToken(word: String): Option[String] = {
    var processed = if (stripPunctuation) word.filter(c => "'!punctuation.contains(c)) else word
    if (lowercase) processed = processed.toLowerCase
    if (processed.length < minLength) return None
    processed = maxLength.fold(processed)(max => processed.take(max))
    if (processed.isEmpty) None else Some(processed)
  }

  /** Split text by whitespace and return a list of Tokens. */
  def tokenize(text: String): List[Token] = {
    text.split("'"\\\\\\\\s+\").filter(_.nonEmpty).zipWithIndex.flatMap { case (word, i) =>
      processToken(word).map { processed =>
        Token(processed, TokenType.STRING, Map(\"position\" -> i, \"original\" -> word))
      }
    }.toList
  }

  /** Convenience: return just the token string values. */
  def tokenizeToStrings(text: String): List[String] =
    tokenize(text).map(_.value)

  /** Tokenize and return tokens with character positions in the original text. */
  def tokenizeWithPositions(text: String): List[(String, Int, Int)] = {
    var currentPos = 0
    val result = mutable.ListBuffer.empty[(String, Int, Int)]

    for (word <- text.split(\"\\\\\\\\s+\").filter(_.nonEmpty)) {
      val start = text.indexOf(word, currentPos)
      val end = start + word.length
      processToken(word).foreach(p => result += ((p, start, end)))
      currentPos = end
    }
    result.toList
  }

  /** Return the number of tokens in the text. */
  def countTokens(text: String): Int = tokenize(text).size
}\"\"\")

